const slotsRaw = $('Get Timing Slots').first().json;
const snapRaw = $('Get Snapshot').first().json;
const slots = slotsRaw.data || slotsRaw || {};
const snap = snapRaw.data || snapRaw;
const funnel = snap.funnel || {};
const risk = snap.risk || {};
const totalLeads = funnel.totalLeads || 0;
const invited = funnel.invited || 0;
const accepted = funnel.accepted || 0;
const acceptanceRate = invited > 0 ? ((accepted / invited) * 100).toFixed(1) : '0.0';
const pendingPct = ((risk.pendingRatio || 0) * 100).toFixed(1);
const slotsJson = JSON.stringify(slots).slice(0, 600);
const weekDate = new Date().toISOString().slice(0, 10);
const prompt = 'Sei un ottimizzatore di timing per LinkedIn automation. Analisi al ' + weekDate + '.\n\nFASCE ORARIE (acceptance rate per slot):\n' + slotsJson + '\n\nCONTESTO FUNNEL:\n- ' + totalLeads + ' leads | ' + invited + ' invitati | ' + accepted + ' accettati\n- Acceptance rate attuale: ' + acceptanceRate + '% | Pending ratio: ' + pendingPct + '%\n\nAnalizza i dati e suggerisci gli orari ottimali per le sessioni della prossima settimana. Output in italiano, max 10 righe:\n\n- Orari consigliati sessione mattina (2-3 opzioni con fascia oraria)\n- Orari consigliati sessione pomeriggio (2-3 opzioni)\n- Orari da evitare (con motivazione breve)\n- Reasoning in 2-3 righe';
const claudeBody = JSON.stringify({ model: 'claude-sonnet-4-6', max_tokens: 400, messages: [{ role: 'user', content: prompt }] });
return [{ json: { claudeBody, weekDate } }];

const response = $input.first().json;
const meta = $('Prepara Prompt').first().json;
let timingText = 'Suggerimenti non disponibili — errore Claude.';
try {
  const text = response.content?.[0]?.text || '';
  if (text.length > 10) timingText = text;
} catch(e) {}
return [{ json: { timingText, weekDate: meta.weekDate } }];
